using UnityEngine;

/// <summary>
/// Ovo da galinha (P5/P6 — EggAbility): objecto PESADO que cai. Causa dano a
/// INIMIGOS quando os atinge com velocidade (cair em cima, ou atirado por uma
/// forma com canGrab/canThrow — ver Carryable/GrabThrowAbility). Pressiona
/// placas de peso (pôr ObjectWeight pesado no prefab).
///
/// Prefab recomendado: SpriteRenderer + Rigidbody2D + Collider2D + EggObject +
/// ObjectWeight (peso alto) + Carryable.
/// </summary>
[RequireComponent(typeof(Rigidbody2D), typeof(Collider2D))]
public class EggObject : MonoBehaviour
{
    [Header("Dano por Impacto")]
    [Tooltip("Dano causado a um inimigo atingido com velocidade suficiente.")]
    public int impactDamage = 2;

    [Tooltip("Velocidade relativa mínima do impacto para causar dano.")]
    public float minImpactSpeed = 5f;

    [Tooltip("Knockback aplicado ao inimigo atingido.")]
    public float impactKnockback = 6f;

    [Header("Quebra")]
    [Tooltip("O ovo parte-se após este número de impactos FORTES (0 = nunca parte).")]
    [Min(0)] public int strongImpactsToBreak = 0;

    public GameObject breakVfxPrefab;
    public AudioClip impactSound;

    private Rigidbody2D _rb;
    private int _strongImpacts;

    private void Awake()
    {
        _rb = GetComponent<Rigidbody2D>();
    }

    private void OnCollisionEnter2D(Collision2D collision)
    {
        float impactSpeed = collision.relativeVelocity.magnitude;
        if (impactSpeed < minImpactSpeed) return;

        if (impactSound != null)
            AudioSource.PlayClipAtPoint(impactSound, transform.position);

        // Dano a inimigos (sem categoria — o ovo não é uma "forma").
        var enemyHealth = collision.collider.GetComponent<EnemyHealth>();
        if (enemyHealth != null)
            enemyHealth.TakeDamage(impactDamage, transform.position, impactKnockback);

        // Quebra após N impactos fortes (opcional).
        if (strongImpactsToBreak > 0)
        {
            _strongImpacts++;
            if (_strongImpacts >= strongImpactsToBreak)
            {
                if (breakVfxPrefab != null)
                    Instantiate(breakVfxPrefab, transform.position, Quaternion.identity);

                Destroy(gameObject);
            }
        }
    }
}
